var ReleaseInterfacesExports = requireReleaseInterfaces();

var BuildInterfacesExports = requireBuildInterfaces();

class PipelineHelper {
    static EnsureValidPipeline(projectName, pipelineName, pipelines) {
        // If definition not found then Throw Error
        if (pipelines == null || pipelines.length == 0) {
            const errorMessage = `Pipeline named "${pipelineName}" not found in project "${projectName}"`;
            throw new PipelineNotFoundError(errorMessage);
        }
        if (pipelines.length > 1) {
            // If more than 1 definition found, throw ERROR
            const errorMessage = `More than 1 Pipeline named "${pipelineName}" found in project "${projectName}"`;
            throw Error(errorMessage);
        }
    }
    static equals(str1, str2) {
        if (str1 === str2) {
            return true;
        }
        if (str1 === null) {
            return false;
        }
        if (str2 === null) {
            return false;
        }
        return str1.trim().toUpperCase() === str2.trim().toUpperCase();
    }
    static processEnv(envVarName) {
        const variable = process.env[envVarName];
        if (!variable) {
            throw new Error(`env.${envVarName} is not set`);
        }
        return variable;
    }
    static isGitHubArtifact(artifact) {
        if (artifact != null && artifact.type != null && artifact.type.toUpperCase() === "GITHUB") {
            return true;
        }
        return false;
    }
    static getErrorAndWarningMessageFromBuildResult(validationResults) {
        let errorMessage = "";
        let warningMessage = "";
        if (validationResults && validationResults.length > 0) {
            const errors = validationResults.filter((result) => {
                return result.result === BuildInterfacesExports.ValidationResult.Error;
            });
            if (errors.length > 0) {
                errorMessage = this._joinValidateResults(errors);
            }
            else {
                warningMessage = this._joinValidateResults(validationResults);
            }
        }
        // Taking into account server errors also which comes not in form of array, like no build queue permissions
        else if (validationResults) {
            errorMessage = this._getErrorMessageFromServer(validationResults);
        }
        return {
            errorMessage: errorMessage,
            warningMessage: warningMessage
        };
    }
    static _joinValidateResults(validateResults) {
        const resultMessages = validateResults.map((validationResult) => {
            return validationResult.message;
        });
        const filtered = resultMessages.filter((message) => !!message);
        return filtered.join(",");
    }
    static _getErrorMessageFromServer(validationResult) {
        let errorMessage = "";
        const result = validationResult;
        if (result) {
            errorMessage = result.message || "";
        }
        if (result && result.serverError && errorMessage.length === 0) {
            errorMessage = result.serverError.message || "";
        }
        return errorMessage;
    }
}

class Logger {
    static LogOutputUrl(url) {
        if (url) {
            setOutput('pipeline-url', url);
            info(`More details on triggered pipeline can be found here : "${url}"`);
        }
    }
    static LogInfo(message) {
        info(message);
    }
    static LogPipelineTriggered(pipelineName, projectName) {
        info(`Pipeline '${pipelineName}' is triggered in project '${projectName}'`);
    }
    static LogPipelineObject(object) {
        debug("Pipeline object : " + this.getPrintObject(object));
    }
    static LogPipelineTriggerInput(input) {
        debug("Input: " + this.getPrintObject(input));
    }
    static LogPipelineTriggerOutput(output) {
        debug("Output: " + this.getPrintObject(output));
    }
    static getPrintObject(object) {
        return JSON.stringify(object, null, 4);
    }
}

class UrlParser {
    static NullOrEmptyProjectUrl = "Project url is null or empty. Specify the valid project url and try again";
    static GetProjectName(projectUrl) {
        if (this.IsNullOrEmpty(projectUrl)) {
            throw new Error(this.NullOrEmptyProjectUrl);
        }
        try {
            projectUrl = projectUrl.trim();
            this.EnsureProjectName(projectUrl);
            const index = projectUrl.lastIndexOf("/");
            const projectNamePart = projectUrl.substring(index + 1);
            const projectName = decodeURI(projectNamePart);
            if (projectName) {
                return projectName;
            }
            else {
                throw Error();
            }
        }
        catch {
            const errorMessage = this.GetUrlParseExceptionMessage(projectUrl);
            throw new Error(errorMessage);
        }
    }
    static GetCollectionUrlBase(projectUrl) {
        if (this.IsNullOrEmpty(projectUrl)) {
            throw new Error(this.NullOrEmptyProjectUrl);
        }
        try {
            projectUrl = projectUrl.trim();
            const collectionUrl = projectUrl.substring(0, projectUrl.lastIndexOf("/"));
            if (collectionUrl) {
                return collectionUrl;
            }
            else {
                throw Error();
            }
        }
        catch {
            const errorMessage = this.GetUrlParseExceptionMessage(projectUrl);
            throw new Error(errorMessage);
        }
    }
    static EnsureProjectName(projectUrl) {
        const index = projectUrl.lastIndexOf("/");
        if (index == (projectUrl.length - 1)) {
            throw Error();
        }
    }
    static GetUrlParseExceptionMessage(projectUrl) {
        const errorMessage = `Failed to parse project url: "${projectUrl}". Specify the valid project url (eg, https://dev.azure.com/organization/project-name or https://server.example.com:8080/tfs/DefaultCollection/project-name)) and try again.`;
        return errorMessage;
    }
    static IsNullOrEmpty(value) {
        return (!value);
    }
}

